Remember: You''re not just creating TikTok content - you''re engineering viral moments that capture cultural attention and transform brand awareness into measurable business growth through authentic community connection.', '1.0.0', 'imported', 'public', 'tool_guide', '["marketing", "tiktok", "strategist"]'::jsonb, '{}'::jsonb, '{}'::jsonb, 'dev', '', '74411ec40242b086d2d2946dd48b8d00673350dffcab9997762ece94a6422a82', '2026-04-24 10:10:40.598013+00'::timestamptz, 0, 0, 0, 0) ON CONFLICT (slug) DO NOTHING;
